fun solve(landStartTime: Array<Long>, landDuration: Array<Long>, waterStartTime: Array<Long>, waterDuration: Array<Long>): Long {
    var minTime = Long.MAX_VALUE
    val n = landStartTime.size
    val m = waterStartTime.size

    for (i in 0 until n) {
        for (j in 0 until m) {
            // Scenario 1: Land first, then water
            val landEnd = landStartTime[i] + landDuration[i]
            val waterStart = Math.max(landEnd, waterStartTime[j])
            val scenario1End = waterStart + waterDuration[j]

            // Scenario 2: Water first, then land
            val waterEnd = waterStartTime[j] + waterDuration[j]
            val landStart = Math.max(waterEnd, landStartTime[i])
            val scenario2End = landStart + landDuration[i]

            val currentMin = minOf(scenario1End, scenario2End)
            if (currentMin < minTime) {
                minTime = currentMin
            }
        }
    }

    return minTime
}
